import DirectMessageItem from "../DirectMessage/DirectMessageItem";

import classes from "./Layout.module.css";

const Layout = () => {
  return (
    <div className={classes["container"]}>
      <Sidebar></Sidebar>
      <ul>
        <DirectMessageItem></DirectMessageItem>{" "}
        <DirectMessageItem></DirectMessageItem>{" "}
        <DirectMessageItem></DirectMessageItem>
      </ul>
    </div>
  );
};

export default Layout;
